{"code": "import os
import yaml
import hashlib
import json
from pathlib import Path
from datetime import datetime

skills_dir = Path("/opt/data/skills")
registry_dir = skills_dir / "_registry"
registry_dir.mkdir(exist_ok=True)

skillopt_map = {
    "version": "skillopt-v2",
    "APEX_version": "自然吞噬版-v2.0",
    "generated_at": datetime.now().isoformat(),
    "engine_mission": "从模型随机输出到确定性、可审计、可量产的闭环工程交付",
    "skills": {}
}

def compute_hash(content: str) -> str:
    return hashlib.sha256(content.encode()).hexdigest()

def extract_tools_from_skill(skill_name: str, skill_dir: Path) -> list:
    """提取 skill 中使用的工具列表"""
    tools = set()
    skill_md = skill_dir / "SKILL.md"

    if skill_md.exists():
        content = skill_md.read_text(encoding="utf-8")
        # 简单工具提取
        tool_keywords = ["terminal", "read_file", "search_files", "write_file", "skill_view",
                        "skill_manage", "memory", "feishu", "browser", "vision", "delegate",
                        "execute_code", "done", "clarify", "todo"]
        for tool in tool_keywords:
            if f'"{tool}"' in content or f"'{tool}'" in content or f"`{tool}`" in content:
                tools.add(tool)

    return sorted(list(tools))

def build_skillopt_entry(name: str, skill_dir: Path) -> dict:
    """构建 skillopt-v2 条目"""
    skill_md = skill_dir / "SKILL.md"

    # 提取 frontmatter
    frontmatter = {}
    if skill_md.exists():
        content = skill_md.read_text(encoding="utf-8")
        if content.startswith("---"):
            parts = content.split("---", 2)
            if len(parts) >= 3:
                try:
                    frontmatter = yaml.safe_load(parts[1]) or {}
                except:
                    pass

    tools = extract_tools_from_skill(name, skill_dir)

    return {
        "api_version": "skillopt-v2",
        "core": {
            "name": name,
            "version": frontmatter.get("version", "2.0.0"),
            "title": frontmatter.get("title") or frontmatter.get("description", "未定义"),
            "description": frontmatter.get("description", "未定义"),
            "author": frontmatter.get("author", "未知"),
            "license": frontmatter.get("license", "MIT"),
            "category": frontmatter.get("category"),
            "tags": frontmatter.get("tags", [])
        },
        "interface": {
            "type": "skill",
            "tools": tools,
            "inputs": ["task", "context", "config"],
            "outputs": ["message", "file", "media", "skill_result"]
        },
        "consumption_contract": {
            "self_probing": True,
            "loop_auditing": True,
            "hash_traceable": True,
            "entropy_reduction": True,
            "self_heal_enabled": True
        },
        "transformation_rules": {
            "converge_to_norm": True,
            "lock_discipline": True,
            "collaborative_entropy_reduction": True
        },
        "task_status": {
            "enabled": True,
            "states": ["pending", "in_progress", "completed", "failed", "cancelled"],
            "default_state": "pending"
        },
        "success_condition": {
            "enabled": True,
            "default": "all_tasks_completed"
        },
        "ingestion_timestamp": datetime.now().isoformat(),
        "status": "skillopt_v2_mapped",
        "hash_signature": compute_hash(json.dumps(name))
    }

# 扫描所有技能
for item in sorted(skills_dir.iterdir()):
    if item.is_dir() and not item.name.startswith("_") and item.name not in [".git"]:
        skill_name = item.name
        skillopt_map["skills"][skill_name] = build_skillopt_entry(skill_name, item)

# 写入 skillopt-map.yaml
output_path = registry_dir / "skillopt-map.yaml"
with open(output_path, "w", encoding="utf-8") as f:
    yaml.dump(skillopt_map, f, allow_unicode=True, default_flow_style=False, sort_keys=False)

# 写入审计日志
audit_log_path = Path("/opt/data/.apex_audit_log.jsonl")
audit_event = {
    "event_type": "skillopt_update_v2",
    "total_skills": len(skillopt_map["skills"]),
    "skillopt_version": skillopt_map["version"],
    "session_hash": compute_hash(json.dumps(skillopt_map))
}
with open(audit_log_path, "a", encoding="utf-8") as f:
    f.write(json.dumps(audit_event, ensure_ascii=False) + "\n")

print(f"✅ 已更新 {skillopt_map['total_skills']} 个技能的 skillopt-v2 协议")
print(f"📁 输出文件: {output_path}")
print(f"📋 审计日志: {audit_log_path}")

# 显示前 3 个技能示例
print("\n📋 skillopt-v2 示例 (前 3 个技能):")
for i, (name, skill) in enumerate(skillopt_map["skills"].items()):
    if i >= 3:
        break
    print(f"  • {name}:")
    print(f"    - api_version: {skill['api_version']}")
    print(f"    - task_status.enabled: {skill['task_status']['enabled']}")
    print(f"    - consumption_contract.self_heal_enabled: {skill['consumption_contract']['self_heal_enabled']}")
"}

